{"cmd":"# Configure nginx for port 80 web interface
cat > /etc/nginx/sites-available/default << 'EOF'
server {
    listen 80 default_server;
    listen [::]:80 default_server;

    server_name _;

    root /var/www/html;
    index index.html;

    location / {
        try_files $uri $uri/ =404;
    }

    # Proxy for VNC web interface (noVNC)
    location /vnc/ {
        proxy_pass http://127.0.0.1:6080/;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "upgrade";
    }
}
EOF

# Create a simple index page
cat > /var/www/html/index.html << 'EOF'
<!DOCTYPE html>
<html>
<head><title>Windows 3.11 VM</title></head>
<body>
<h1>Windows 3.11 for Workgroups VM</h1>
<p>VNC Display: :1 (Port 5901)</p>
<p>QEMU Monitor: tcp:4444</p>
<p>Status: Running</p>
</body>
</html>
EOF

nginx -t && nginx
echo "Nginx started"
ss -tlnp | grep ':80'"}

